DetectionRule.DetectionLogic:
let AutorunPaths = dynamic([ "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Run", "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\RunOnce", "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\RunOnceEx", "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\RunServices", "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\RunServicesOnce", "HKCU\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Run", "HKCU\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\RunOnce", "HKLM\\SOFTWARE\\Wow6432Node\\Microsoft\\Windows\\CurrentVersion\\Run", "HKLM\\SOFTWARE\\Wow6432Node\\Microsoft\\Windows\\CurrentVersion\\RunOnce", "HKCU\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\User Shell Folders\\Startup", "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Shell Folders\\Common Startup" ]);
let SuspiciousRunValues = dynamic([ "powershell", "cmd.exe", "wscript", "cscript", "rundll32", "regsvr32", "mshta", "certutil", "bitsadmin", "schtasks", "wmic", "msiexec", "installutil", "python", "wsl", "bash" ]);
// Detect registry value creation/modification in autorun locations DeviceRegistryEvents | where Timestamp > ago(4h) | where RegistryKey has_any (AutorunPaths) and ActionType in~ ("RegistryValueSet", "RegistryValueCreated") | extend ValueName = tostring(RegistryValueName) | extend ValueData = tostring(RegistryValue) | extend ValueLower = tolower(ValueData) | where ValueLower has_any (SuspiciousRunValues) or ValueLower matches regex @".*\\(powershell|cmd|wscript|cscript|rundll32|regsvr32).*\.(exe|ps1|vbs|js|bat|cmd).*" or ValueLower contains "http" or ValueLower contains "https" or ValueLower contains "ftp" or ValueLower contains "\\\\" | extend RiskScore = case( ValueLower has_any ("powershell", "cmd.exe", "rundll32", "regsvr32", "mshta"), 92, ValueLower contains "http" or ValueLower contains "https", 88, ValueLower contains "\\\\", 85, true, 80 ) | where RiskScore >= 80 | summarize AutorunModifications = count(), RiskScore = max(RiskScore), Values = makeset(ValueName) by DeviceId, RegistryKey, AccountName, ProcessName | where AutorunModifications >= 1
// Also detect unusual parent processes modifying autorun keys union ( DeviceRegistryEvents | where Timestamp > ago(4h) | where RegistryKey has_any (AutorunPaths) and ActionType in~ ("RegistryValueSet", "RegistryValueCreated") and InitiatingProcessFileName !in~ ("regedit.exe", "powershell.exe", "cmd.exe", "msiexec.exe", "SystemSettings.exe") and InitiatingProcessFileName !startswith "Windows Defender" and InitiatingProcessFileName !startswith "MsMpEng" | extend ProcessLower = tolower(InitiatingProcessFileName) | where ProcessLower !contains "defender" and ProcessLower !contains "msmpeng" | summarize UnusualModifications = count(), UniqueKeys = dcount(RegistryKey) by DeviceId, InitiatingProcessFileName, AccountName | where UnusualModifications >= 2 ) | extend FinalRisk = case( AutorunModifications >= 3 or UnusualModifications >= 3, "Critical", AutorunModifications >= 1 or UnusualModifications >= 2, "High", "Medium" ) | project-reorder Timestamp, DeviceId, FinalRisk, AutorunModifications, ProcessName

let SuspiciousTaskCommands = dynamic([ "schtasks.exe", "schtasks", "Schedule.Service", "taskschd.msc", "New-ScheduledTask", "Register-ScheduledTask", "Create", "/Create", "/create", "ONLOGON", "ONSTART", "ONIDLE", "SCF", "JOB" ]);
let HiddenTaskIndicators = dynamic([ "/RL HIGHEST", "/RU SYSTEM", "/TN \\\", "/F", "/XML", ".xml", "HiddenTask", "SystemTask" ]);
let SuspiciousTaskNames = dynamic([ "Update", "Sync", "Task", "Service", "Helper", "Windows", "System", "Security", "Defender", "OneDrive", "Google", "Microsoft" ]);
// Detect scheduled task creation via command line DeviceProcessEvents | where Timestamp > ago(4h) | where (FileName in~ ("schtasks.exe", "powershell.exe", "cmd.exe", "wscript.exe", "cscript.exe") and ProcessCommandLine has_any (SuspiciousTaskCommands)) or (FileName == "powershell.exe" and ProcessCommandLine has_any ("New-ScheduledTask", "Register-ScheduledTask", "Schedule.Service")) | extend TaskOperation = case( ProcessCommandLine has_any ("/Create", "/create", "Create", "/TN"), "TaskCreation", ProcessCommandLine has "/XML", "TaskImport", ProcessCommandLine has "/RL HIGHEST", "PrivilegeEscalation", "Other" ) | where TaskOperation != "Other" | extend HiddenTask = case( ProcessCommandLine has_any (HiddenTaskIndicators), true, ProcessCommandLine has "/TN \\\" and ProcessCommandLine contains "System32", true, false ) | where HiddenTask == true or TaskOperation in~ ("TaskImport", "PrivilegeEscalation") | summarize TaskCreations = count(), HiddenTasks = makeset(HiddenTask), Commands = makeset(ProcessCommandLine) by DeviceId, FileName, InitiatingProcessFileName, AccountName | where TaskCreations >= 1
// Also detect Task Scheduler API usage union ( DeviceApiCalls | where Timestamp > ago(4h) | where ApiName in~ ("ITaskService", "ITaskFolder", "RegisterTask") and InitiatingProcessFileName !in~ ("taskschd.msc", "mmc.exe", "powershell.exe") | summarize ApiCalls = count() by DeviceId, InitiatingProcessFileName | where ApiCalls >= 3 ) | extend FinalRisk = case( HiddenTasks contains true, "Critical", TaskCreations >= 3 or ApiCalls >= 5, "High", TaskCreations >= 1, "Medium", "Low" ) | where FinalRisk in~ ("Critical", "High", "Medium") | project-reorder Timestamp, DeviceId, FinalRisk, TaskCreations, FileName

let WMIPersistenceTools = dynamic([ "wmic", "WMIC.exe", "powershell", "pwsh", "wmi", "wbemtest" ]);
let WMIConsumerCommands = dynamic([ "FilterToConsumerBinding", "__EventFilter", "__EventConsumer", "__FilterToConsumerBinding", "CommandLineEventConsumer", "ActiveScriptEventConsumer", "LogFileEventConsumer" ]);
// Detect WMI persistence creation via command line DeviceProcessEvents | where Timestamp > ago(8h) | where (FileName in~ (WMIPersistenceTools) and ProcessCommandLine has_any (WMIConsumerCommands)) or (ProcessCommandLine contains "FilterToConsumerBinding") or (FileName == "powershell.exe" and ProcessCommandLine contains "Set-WmiInstance") or (FileName == "powershell.exe" and ProcessCommandLine contains "__EventConsumer") | extend PersistenceType = case( ProcessCommandLine contains "CommandLineEventConsumer", "Command Execution", ProcessCommandLine contains "ActiveScriptEventConsumer", "Script Execution", ProcessCommandLine contains "LogFileEventConsumer", "Log Manipulation", "Unknown WMI Persistence" ) | where PersistenceType != "Unknown WMI Persistence" | summarize WmiPersistenceCreations = count(), PersistenceTypes = makeset(PersistenceType), Commands = makeset(ProcessCommandLine) by DeviceId, FileName, InitiatingProcessFileName, AccountName | where WmiPersistenceCreations >= 1
// Also detect WMI namespace modifications for persistence union ( DeviceRegistryEvents | where Timestamp > ago(8h) | where RegistryKey has "ROOT\\subscription" and RegistryKey has_any ("Filter", "Consumer", "Binding") and ActionType in~ ("RegistryValueSet", "RegistryKeyCreated") and InitiatingProcessFileName !in~ ("System", "svchost.exe", "wmiprvse.exe") | summarize WmiRegistryMods = count(), RegistryKeys = makeset(RegistryKey) by DeviceId, InitiatingProcessFileName, AccountName | where WmiRegistryMods >= 1 ) | extend FinalRisk = case( WmiPersistenceCreations >= 2 or WmiRegistryMods >= 2, "High", WmiPersistenceCreations == 1 or WmiRegistryMods == 1, "Medium", "Low" ) | where FinalRisk in~ ("High", "Medium") | project-reorder Timestamp, DeviceId, FinalRisk, WmiPersistenceCreations, FileName

let ServiceCreationCommands = dynamic([ "sc.exe create", "sc create", "sc\\.exe create", "New-Service", "InstallUtil", "installutil.exe", "sc.exe config", "sc config" ]);
let SuspiciousServiceNames = dynamic([ "Spooler", "EventLog", "SamSs", "Lsa", "WinDefend", "Schedule", "Themes", "AudioSrv", "BITS", "wuauserv", "Update", "Security", "System", "Windows", "Service" ]);
let SuspiciousBinPaths = dynamic([ "\\\\", "%TEMP%", "C:\\Users\\", "C:\\ProgramData\\", ".exe", ".dll", ".scr", ".vbs", ".ps1", ".bat", ".cmd" ]);
// Detect service creation via sc.exe or PowerShell DeviceProcessEvents | where Timestamp > ago(4h) | where (FileName in~ ("sc.exe", "powershell.exe", "cmd.exe") and ProcessCommandLine has_any (ServiceCreationCommands)) or (FileName == "InstallUtil.exe" and ProcessCommandLine contains "/U") | extend ServiceName = extract(@"create\\s+([^\s]+)", 1, ProcessCommandLine, typeof(string)) | extend BinPath = extract(@"binPath\\s*=\\s*([^\s]+)", 1, ProcessCommandLine, typeof(string)) | extend StartType = case( ProcessCommandLine contains "start= auto" or ProcessCommandLine contains "start= AUTO", "Auto", ProcessCommandLine contains "start= demand" or ProcessCommandLine contains "start= DEMAND", "Manual", "Unknown" ) | where ServiceName in~ (SuspiciousServiceNames) or BinPath has_any (SuspiciousBinPaths) or StartType == "Auto" or isnotempty(ServiceName) | summarize ServiceCreations = count(), UniqueServices = dcount(ServiceName), Commands = makeset(ProcessCommandLine) by DeviceId, FileName, InitiatingProcessFileName, AccountName | where ServiceCreations >= 1
// Also detect service modifications union ( DeviceRegistryEvents | where Timestamp > ago(4h) | where RegistryKey has "SYSTEM\\CurrentControlSet\\Services" and RegistryKey !endswith "\\Enum" and RegistryKey !endswith "\\Security" and RegistryValue contains ".exe" and ActionType in~ ("RegistryValueSet", "RegistryKeyCreated") and InitiatingProcessFileName !in~ ("services.exe", "System", "mmc.exe") | extend ServiceName = tostring(split(RegistryKey, '\\')[-1]) | where ServiceName !in~ ("", "SamSs", "Lsa", "EventLog", "Spooler") // Exclude core services | summarize ServiceModifications = count(), ServiceNames = makeset(ServiceName) by DeviceId, InitiatingProcessFileName, AccountName | where ServiceModifications >= 1 ) | extend FinalRisk = case( ServiceCreations >= 2 or ServiceModifications >= 2, "High", ServiceCreations == 1 or ServiceModifications == 1, "Medium", "Low" ) | where FinalRisk in~ ("High", "Medium") | project-reorder Timestamp, DeviceId, FinalRisk, ServiceCreations, FileName

let StartupFolders = dynamic([ "\\Microsoft\\Windows\\Start Menu\\Programs\\Startup\\", "\\Start Menu\\Programs\\Startup\\", "\\AppData\\Roaming\\Microsoft\\Windows\\Start Menu\\Programs\\Startup\\", "\\ProgramData\\Microsoft\\Windows\\Start Menu\\Programs\\Startup\\" ]);
let SuspiciousExtensions = dynamic([".exe", ".scr", ".pif", ".cmd", ".bat", ".vbs", ".ps1", ".js", ".jse", ".wsf"]);
// Detect file creation/modification in startup folders DeviceFileEvents | where Timestamp > ago(4h) | where FolderPath has_any (StartupFolders) and ActionType in~ ("FileCreated", "FileModified", "FileRenamed") | extend Extension = tostring(split(FileName, '.')[-1]) | where Extension in~ (SuspiciousExtensions) or FileName contains ".exe" or FileName contains ".scr" | extend FilePath = strcat(FolderPath, FileName) | extend RiskScore = case( Extension in~ ("exe", "scr", "pif"), 90, Extension in~ ("vbs", "ps1", "js", "jse", "wsf"), 85, Extension in~ ("bat", "cmd"), 75, true, 60 ) | where RiskScore >= 75 or InitiatingProcessFileName !in~ ("explorer.exe", "UserAccountControl.exe") | summarize StartupModifications = count(), RiskScore = max(RiskScore), Files = makeset(FileName) by DeviceId, FolderPath, InitiatingProcessFileName, AccountName, Extension | where StartupModifications >= 1 | extend FinalRisk = case( RiskScore >= 85 and Extension in~ ("exe", "scr"), "High", RiskScore >= 75, "Medium", "Low" ) | where FinalRisk in~ ("High", "Medium") | project-reorder Timestamp, DeviceId, FinalRisk, StartupModifications, FileName, Extension
